import React from 'react';
import { Article } from '../../types';

interface ArticleCardProps {
  article: Article;
  onClick: () => void;
  style?: React.CSSProperties;
}

const ArticleCard: React.FC<ArticleCardProps> = ({ article, onClick, style }) => {
  // Category-specific color mapping for the badges
  const getCategoryColor = (category: string) => {
    switch (category) {
      case 'Economic Insights': return 'text-[#7fe8d8] bg-[#000000]/60';
      case 'Political Commentary': return 'text-[#7fe8d8] bg-[#000000]/60';
      case 'Social Responsibility': return 'text-[#7fe8d8] bg-[#000000]/60';
      default: return 'text-[#7fe8d8] bg-[#000000]/60';
    }
  };

  return (
    <div 
      onClick={onClick} 
      className="cursor-pointer group bg-[#111115] border border-white/5 rounded-2xl overflow-hidden h-full flex flex-col transition-all duration-300 hover:border-white/10 hover:shadow-2xl hover:shadow-black"
      style={style}
    >
      <div className="relative overflow-hidden aspect-[16/10]">
        <img 
          src={article.imageUrl} 
          alt={article.title} 
          loading="lazy" 
          className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 ease-out" 
        />
        <div className={`absolute top-4 left-4 backdrop-blur-md px-3 py-1.5 rounded-sm`}>
