        </button>

        {/* Nav & Search Right */}
        <div className="flex items-center space-x-2">
          <nav className="hidden lg:flex items-center space-x-1 mr-6">
            {navItems.map(item => (
                <NavLink key={item.page} page={item.page} activePage={activePage} onNavClick={onNavClick}>
                  {item.label}
